import { GoogleGenAI } from "@google/genai";

const getClient = () => {
  const apiKey = process.env.API_KEY;
  if (!apiKey) {
    throw new Error("API Key not found");
  }
  return new GoogleGenAI({ apiKey });
};

export const getAgriculturalAdvice = async (query: string): Promise<string> => {
  try {
    const ai = getClient();
    const model = 'gemini-3-flash-preview';

    const systemInstruction = `
      أنت خبير زراعي متخصص في منطقة تهامة في اليمن.
      دورك هو مساعدة المزارعين والتجار بتقديم نصائح علمية وعملية.
      استخدم اللهجة المفهومة للمزارعين العرب، وركز على المحاصيل المشهورة في تهامة مثل المانجو، الطماطم، والحبوب.
      قدم نصائح حول الري، الأسمدة، ومكافحة الآفات.
    `;

    const response = await ai.models.generateContent({
      model: model,
      contents: query,
      config: {
        systemInstruction: systemInstruction,
        temperature: 0.7,
      }
    });

    return response.text || "عذراً، لم أتمكن من الحصول على إجابة في الوقت الحالي.";
  } catch (error) {
    console.error("Gemini API Error:", error);
    return "حدث خطأ أثناء الاتصال بالخبير الذكي. يرجى المحاولة لاحقاً.";
  }
};

