import React, { useState, useRef, useEffect } from 'react';
import { Send, Bot, User, Loader2, Sparkles } from 'lucide-react';
import { ChatMessage } from '../types';
import { getAgriculturalAdvice } from '../services/geminiService';

export const AIAdvisor: React.FC = () => {
  const [messages, setMessages] = useState<ChatMessage[]>([
    {
      id: 'welcome',
      role: 'model',
      text: 'مرحباً بك يا أخي المزارع. أنا مرشدك الزراعي الذكي من منصة عطاء تهامة. كيف يمكنني مساعدتك اليوم في تحسين محصولك أو حل مشكلة زراعية؟',
      timestamp: new Date()
    }
  ]);
  const [input, setInput] = useState('');
  const [isLoading, setIsLoading] = useState(false);
  const messagesEndRef = useRef<HTMLDivElement>(null);

  const scrollToBottom = () => {
    messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  };

  useEffect(() => {
    scrollToBottom();
  }, [messages]);

  const handleSend = async () => {
    if (!input.trim()) return;

    const userMsg: ChatMessage = {
      id: Date.now().toString(),
      role: 'user',
      text: input,
      timestamp: new Date()
    };

    setMessages(prev => [...prev, userMsg]);
    setInput('');
    setIsLoading(true);

    try {
      const responseText = await getAgriculturalAdvice(input);
      const aiMsg: ChatMessage = {
        id: (Date.now() + 1).toString(),
        role: 'model',
        text: responseText,
        timestamp: new Date()
      };
      setMessages(prev => [...prev, aiMsg]);
    } catch (error) {
      console.error(error);
    } finally {
      setIsLoading(false);
    }
  };

  const handleKeyPress = (e: React.KeyboardEvent) => {
    if (e.key === 'Enter' && !e.shiftKey) {
      e.preventDefault();
      handleSend();
    }
  };

  return (
    <div className="max-w-4xl mx-auto p-4 h-[calc(100vh-80px)]">
      <div className="bg-white rounded-2xl shadow-xl h-full flex flex-col border border-gray-200 overflow-hidden">
        {/* Header */}
        <div className="bg-gradient-to-l from-primary-700 to-primary-600 p-4 flex items-center gap-3 shadow-md">
          <div className="bg-white/20 p-2 rounded-full backdrop-blur-sm">
            <Sparkles className="h-6 w-6 text-yellow-300" />
          </div>
          <div>
            <h2 className="text-white font-bold text-lg">المرشد الزراعي الذكي</h2>
            <p className="text-primary-100 text-xs opacity-90">مدعوم بالذكاء الاصطناعي (Gemini)</p>
          </div>
        </div>

        {/* Chat Area */}
        <div className="flex-1 overflow-y-auto p-4 space-y-4 bg-gray-50/50">
          {messages.map((msg) => (
            <div
              key={msg.id}
              className={`flex items-start gap-3 ${msg.role === 'user' ? 'flex-row-reverse' : ''}`}
            >
              <div className={`w-10 h-10 rounded-full flex items-center justify-center shrink-0 ${
                msg.role === 'user' ? 'bg-primary-100' : 'bg-blue-100'
              }`}>
                {msg.role === 'user' ? <User className="h-6 w-6 text-primary-700" /> : <Bot className="h-6 w-6 text-blue-700" />}
              </div>

              <div className={`max-w-[80%] rounded-2xl px-5 py-3 shadow-sm ${
                msg.role === 'user' 
                  ? 'bg-primary-600 text-white rounded-tl-none' 
                  : 'bg-white text-gray-800 border border-gray-100 rounded-tr-none'
              }`}>
                <p className="text-sm leading-relaxed whitespace-pre-wrap">{msg.text}</p>
                <span className={`text-[10px] block mt-1 ${
                  msg.role === 'user' ? 'text-primary-200' : 'text-gray-400'
                }`}>
                  {msg.timestamp.toLocaleTimeString('ar-YE', { hour: '2-digit', minute: '2-digit' })}
                </span>
              </div>
            </div>
          ))}
          {isLoading && (
            <div className="flex items-center gap-2 text-gray-400 text-sm mr-12">
              <Loader2 className="h-4 w-4 animate-spin" />
              جاري تحليل السؤال وكتابة النصائح...
            </div>
          )}
          <div ref={messagesEndRef} />
        </div>

        {/* Input Area */}
        <div className="p-4 bg-white border-t border-gray-100">
          <div className="flex gap-2 relative">
            <input
              type="text"
              value={input}
              onChange={(e) => setInput(e.target.value)}
              onKeyDown={handleKeyPress}
              placeholder="اكتب سؤالك هنا... (مثلاً: كيف أعالج ذبول الطماطم؟)"
              className="flex-1 bg-gray-100 text-gray-800 rounded-xl px-4 py-3 focus:outline-none focus:ring-2 focus:ring-primary-500 transition-all pl-12"
              disabled={isLoading}
            />
            <button
              onClick={handleSend}
              disabled={isLoading || !input.trim()}
              className="absolute left-2 top-2 bottom-2 bg-primary-600 text-white p-2 rounded-lg hover:bg-primary-700 disabled:opacity-50 disabled:hover:bg-primary-600 transition-colors flex items-center justify-center aspect-square"
            >
              {isLoading ? <Loader2 className="h-5 w-5 animate-spin" /> : <Send className="h-5 w-5 rotate-180" />}
            </button>
          </div>
          <p className="text-center text-xs text-gray-400 mt-2">
            يمكن للمرشد الذكي أن يخطئ. يرجى مراجعة الخبراء الميدانيين في الحالات الحرجة.
          </p>
        </div>
      </div>
    </div>
  );
};

