export const UserChat: React.FC = () => {
  const [activeChat, setActiveChat] = useState<string | null>(null);
  const [messageInput, setMessageInput] = useState('');

  // Mock chat history for the active chat
  const [chatHistory, setChatHistory] = useState([
    { id: 1, text: 'السلام عليكم، هل محصول المانجو متوفر؟', sender: 'me', time: '10:00 ص' },
    { id: 2, text: 'وعليكم السلام، نعم متوفر قطفة اليوم.', sender: 'other', time: '10:05 ص' },
    { id: 3, text: 'ممتاز، أريد حجز 50 سلة للسوق المركزي.', sender: 'me', time: '10:10 ص' },
    { id: 4, text: 'نعم، الكمية متوفرة ويمكن شحنها غداً.', sender: 'other', time: '10:30 ص' },
  ]);

  const activeContact = MOCK_CONVERSATIONS.find(c => c.id === activeChat);

  const handleSend = () => {
    if (!messageInput.trim()) return;
    setChatHistory([...chatHistory, { 
      id: Date.now(), 
      text: messageInput, 
      sender: 'me', 
      time: new Date().toLocaleTimeString('ar-YE', {hour:'2-digit', minute:'2-digit'}) 
    }]);
    setMessageInput('');
  };

  return (
    <div className="h-[calc(100vh-80px)] max-w-7xl mx-auto p-4 flex gap-4">
      {/* Sidebar List */}
      <div className={`w-full md:w-1/3 bg-white rounded-2xl shadow-md border border-gray-200 flex flex-col ${activeChat ? 'hidden md:flex' : 'flex'}`}>
        <div className="p-4 border-b border-gray-100">
          <h2 className="text-xl font-bold text-gray-800 mb-4">الرسائل</h2>
          <div className="relative">
             <Search className="absolute right-3 top-2.5 h-4 w-4 text-gray-400" />
             <input type="text" placeholder="بحث في المحادثات..." className="w-full bg-gray-50 border border-gray-200 rounded-lg py-2 pr-9 pl-4 text-sm focus:outline-none focus:border-primary-500" />
          </div>
        </div>
        <div className="flex-1 overflow-y-auto">
          {MOCK_CONVERSATIONS.map(chat => (
            <div 
              key={chat.id} 
              onClick={() => setActiveChat(chat.id)}
              className={`p-4 flex items-center gap-3 cursor-pointer hover:bg-gray-50 transition-colors border-b border-gray-50 ${activeChat === chat.id ? 'bg-primary-50' : ''}`}
            >
              <div className="w-12 h-12 rounded-full bg-primary-100 flex items-center justify-center text-primary-700 font-bold text-lg">
                {chat.avatar}
              </div>
              <div className="flex-1 min-w-0">
                <div className="flex justify-between items-baseline mb-1">
                  <h3 className="font-bold text-gray-900 truncate">{chat.contactName}</h3>
                  <span className="text-xs text-gray-400">{chat.timestamp}</span>
                </div>
                <p className="text-sm text-gray-500 truncate">{chat.lastMessage}</p>
              </div>
              {chat.unread > 0 && (
                <div className="w-5 h-5 bg-red-500 rounded-full flex items-center justify-center text-white text-xs font-bold">
                  {chat.unread}
                </div>
              )}
            </div>
          ))}
        </div>
      </div>

      {/* Chat Area */}
      <div className={`w-full md:w-2/3 bg-white rounded-2xl shadow-md border border-gray-200 flex-col ${activeChat ? 'flex' : 'hidden md:flex'}`}>
        {activeChat ? (
          <>
            <div className="p-4 border-b border-gray-100 flex justify-between items-center bg-gray-50 rounded-t-2xl">
              <div className="flex items-center gap-3">
                <button onClick={() => setActiveChat(null)} className="md:hidden text-gray-500">
                   ←
                </button>
                <div className="w-10 h-10 rounded-full bg-primary-100 flex items-center justify-center text-primary-700 font-bold">
                  {activeContact?.avatar}
                </div>
                <div>
                   <h3 className="font-bold text-gray-900">{activeContact?.contactName}</h3>
                   <span className="text-xs text-green-600 flex items-center gap-1">● متصل الآن</span>
                </div>
              </div>
              <button className="p-2 rounded-full hover:bg-white text-gray-600">
                 <Phone className="h-5 w-5" />
              </button>
            </div>

            <div className="flex-1 overflow-y-auto p-4 space-y-4">
              {chatHistory.map(msg => (
                <div key={msg.id} className={`flex ${msg.sender === 'me' ? 'justify-end' : 'justify-start'}`}>
                  <div className={`max-w-[70%] px-4 py-2 rounded-2xl ${
                    msg.sender === 'me' 
                      ? 'bg-primary-600 text-white rounded-tl-none' 
                      : 'bg-gray-100 text-gray-800 rounded-tr-none'
                  }`}>
                    <p>{msg.text}</p>
                    <span className={`text-[10px] block mt-1 text-left ${msg.sender === 'me' ? 'text-primary-200' : 'text-gray-400'}`}>
                      {msg.time}
                    </span>
                  </div>
                </div>
              ))}
            </div>

            <div className="p-4 border-t border-gray-100">
               <div className="flex gap-2">
                 <input 
                   type="text" 
                   value={messageInput}
                   onChange={(e) => setMessageInput(e.target.value)}
                   onKeyDown={(e) => e.key === 'Enter' && handleSend()}
                   placeholder="اكتب رسالتك هنا..."
                   className="flex-1 bg-gray-50 border border-gray-200 rounded-lg px-4 py-2 focus:outline-none focus:ring-2 focus:ring-primary-500"
                 />
                 <button 
                   onClick={handleSend}
                   className="bg-primary-600 text-white p-2 rounded-lg hover:bg-primary-700"
                 >
                   <Send className="h-5 w-5 rotate-180" />
                 </button>
               </div>
            </div>
          </>
        ) : (
          <div className="flex-1 flex flex-col items-center justify-center text-gray-400">
             <MessageSquare className="h-16 w-16 mb-4 opacity-20" />
             <p>اختر محادثة للبدء في التواصل</p>
          </div>
        )}
      </div>
    </div>
  );
};

import React, { useState } from 'react';
import { Search, MapPin, Tag, Plus, MessageCircle } from 'lucide-react';
import { Product, ProductCategory } from '../types';

interface MarketplaceProps {
  products: Product[];
  onAddToCart: (product: Product) => void;
  onContact: (sellerId: string) => void;
}

export const Marketplace: React.FC<MarketplaceProps> = ({ products, onAddToCart, onContact }) => {
  const [filter, setFilter] = useState<string>('all');
  const [searchTerm, setSearchTerm] = useState('');

  const filteredProducts = products.filter(p => {
    const matchesCategory = filter === 'all' || p.category === filter;
    const matchesSearch = p.name.includes(searchTerm) || p.sellerName.includes(searchTerm);
    return matchesCategory && matchesSearch;
  });

  return (
    <div className="p-6 max-w-7xl mx-auto">
      <div className="mb-8 text-center">
        <h2 className="text-3xl font-bold text-gray-800 mb-4">السوق الزراعي</h2>
        <p className="text-gray-600 max-w-2xl mx-auto">تصفح أحدث المنتجات الزراعية من مزارع تهامة مباشرة إلى المستهلك والتجار.</p>
      </div>

      {/* Filters and Search */}
      <div className="bg-white p-4 rounded-lg shadow-sm border border-gray-100 mb-8 sticky top-20 z-10">
        <div className="flex flex-col md:flex-row gap-4 items-center justify-between">
          <div className="relative w-full md:w-1/3">
            <Search className="absolute right-3 top-2.5 h-5 w-5 text-gray-400" />
            <input
              type="text"
              placeholder="ابحث عن منتج أو مزارع..."
              className="w-full pr-10 pl-4 py-2 border border-gray-300 rounded-lg focus:ring-2 focus:ring-primary-500 focus:border-transparent outline-none"
              value={searchTerm}
              onChange={(e) => setSearchTerm(e.target.value)}
            />
          </div>

          <div className="flex gap-2 overflow-x-auto w-full md:w-auto pb-2 md:pb-0 scrollbar-hide">
            <button
              onClick={() => setFilter('all')}
              className={`px-4 py-2 rounded-full text-sm font-medium whitespace-nowrap transition-colors ${
                filter === 'all' ? 'bg-primary-600 text-white' : 'bg-gray-100 text-gray-600 hover:bg-gray-200'
              }`}
            >
              الكل
            </button>
            {Object.values(ProductCategory).map((cat) => (
              <button
                key={cat}
                onClick={() => setFilter(cat)}
                className={`px-4 py-2 rounded-full text-sm font-medium whitespace-nowrap transition-colors ${
                  filter === cat ? 'bg-primary-600 text-white' : 'bg-gray-100 text-gray-600 hover:bg-gray-200'
                }`}
              >
                {cat}
              </button>
            ))}
          </div>
        </div>
      </div>

      {/* Grid */}
      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
        {filteredProducts.map((product) => (
          <div key={product.id} className="bg-white rounded-xl shadow-md overflow-hidden hover:shadow-lg transition-shadow duration-300 border border-gray-100 group flex flex-col">
            <div className="relative h-48 overflow-hidden">
              <img 
                src={product.image} 
                alt={product.name} 
                className="w-full h-full object-cover transform group-hover:scale-110 transition-transform duration-500" 
              />
              <span className="absolute top-2 right-2 bg-white/90 backdrop-blur text-primary-700 text-xs font-bold px-2 py-1 rounded-full flex items-center gap-1">
                <Tag className="h-3 w-3" />
                {product.category}
              </span>
            </div>

            <div className="p-5 flex-1 flex flex-col">
              <div className="flex justify-between items-start mb-2">
                <h3 className="text-xl font-bold text-gray-800">{product.name}</h3>
                <span className="text-primary-600 font-bold bg-primary-50 px-2 py-1 rounded text-sm">
                  {product.price} ريال
                </span>
              </div>

              <p className="text-gray-500 text-sm mb-4 line-clamp-2">{product.description}</p>

              <div className="mt-auto border-t border-gray-100 pt-4 flex flex-col gap-2">
                <div className="flex items-center text-gray-600 text-sm">
                  <MapPin className="h-4 w-4 ml-1 text-gray-400" />
                  {product.location}
                </div>
                <div className="flex items-center justify-between mt-2">
                  <span className="text-xs text-gray-500">البائع: {product.sellerName}</span>
                  <span className="text-xs bg-gray-100 px-2 py-1 rounded text-gray-600">{product.unit}</span>
                </div>
                <div className="flex gap-2 mt-3">
                  <button 
                    onClick={() => onAddToCart(product)}
                    className="flex-1 bg-primary-600 text-white py-2 rounded-lg font-medium hover:bg-primary-700 transition-colors flex items-center justify-center gap-2 text-sm"
                  >
                    <Plus className="h-4 w-4" />
                    إضافة للسلة
                  </button>
                  <button 
                    onClick={() => onContact(product.sellerName)}
                    className="px-3 bg-gray-100 text-gray-600 py-2 rounded-lg font-medium hover:bg-gray-200 transition-colors"
                    title="تواصل مع البائع"
                  >
                    <MessageCircle className="h-5 w-5" />
                  </button>
                </div>
              </div>
            </div>
          </div>
        ))}
      </div>

      {filteredProducts.length === 0 && (
        <div className="text-center py-20 bg-white rounded-xl border border-dashed border-gray-300">
          <p className="text-gray-500 text-lg">لا توجد منتجات مطابقة لبحثك حالياً.</p>
        </div>
      )}
    </div>
  );
};

