// --- MAIN APP COMPONENT ---
const App: React.FC = () => {
  const [currentView, setCurrentView] = useState('home');
  const [userRole, setUserRole] = useState<UserRole | null>(null);
  const [products, setProducts] = useState<Product[]>(INITIAL_PRODUCTS);
  const [cart, setCart] = useState<CartItem[]>([]);

  // Data State
  const [myOrders, setMyOrders] = useState<Order[]>(INITIAL_ORDERS);
  const [shipments, setShipments] = useState<Order[]>(INITIAL_SHIPMENTS);

  const handleLogin = (role: UserRole) => {
    setUserRole(role);
    setCurrentView('home');
  };

  const handleLogout = () => {
    setUserRole(null);
    setCart([]);
    setCurrentView('home');
  };

  const handleAddToCart = (product: Product) => {
    setCart(prev => {
      const existing = prev.find(item => item.id === product.id);
      if (existing) {
        return prev.map(item => item.id === product.id ? { ...item, quantity: item.quantity + 1 } : item);
      }
      return [...prev, { ...product, quantity: 1 }];
    });
    alert('تم إضافة المنتج للسلة');
  };

  const handleContactSeller = (sellerName: string) => {
    setCurrentView('messages');
  };

  const handleRemoveFromCart = (id: string) => {
    setCart(prev => prev.filter(item => item.id !== id));
  };

  const handleCheckout = () => {
    const total = cart.reduce((sum, item) => sum + (item.price * item.quantity), 0) + 2000;
    const newOrder: Order = {
      id: `ord-${Date.now()}`,
      items: [...cart],
      total: total,
      status: 'pending',
      date: new Date().toLocaleDateString('en-CA'),
    };
    setMyOrders([newOrder, ...myOrders]);
    setCart([]);
    setCurrentView('orders');
  };

  const handleAddProduct = (product: Product) => {
    setProducts(prev => [product, ...prev]);
    setCurrentView('market');
    alert('تم إضافة المنتج بنجاح إلى السوق');
  };

  const handleUpdateStatus = (orderId: string, newStatus: Order['status']) => {
    setShipments(prev => prev.map(order => 
      order.id === orderId ? { ...order, status: newStatus } : order
    ));
  };

  if (!userRole) {
    return <LoginScreen onLogin={handleLogin} />;
  }

  const renderView = () => {
    switch (currentView) {
      case 'home':
        return <HomeView setView={setCurrentView} userRole={userRole} />;
      case 'market':
        return <Marketplace products={products} onAddToCart={handleAddToCart} onContact={handleContactSeller} />;
      case 'add-product':
        return <ProductForm onAddProduct={handleAddProduct} onCancel={() => setCurrentView('home')} sellerName="فراس الرمعي (مزارع)" />;
      case 'cart':
        return <Cart items={cart} onRemove={handleRemoveFromCart} onCheckout={handleCheckout} />;
      case 'orders':
        return <Orders orders={myOrders} userRole={userRole} title="طلباتي" />;
      case 'shipments':
        return <Orders orders={shipments} userRole={userRole} title="شحنات للتوصيل" onUpdateStatus={handleUpdateStatus} />;
      case 'messages':
        return <UserChat />;
      case 'advisor':
        return <AIAdvisor />;
      case 'guidance':
        return <GuidanceLibrary />;
      case 'dashboard':
        return <StatsDashboard />;
      default:
        return <div className="p-10 text-center text-gray-500">جاري العمل على هذه الصفحة...</div>;
    }
  };

  return (
    <div className="min-h-screen bg-gray-50 font-sans">
      <Navigation 
        currentView={currentView} 
        setView={setCurrentView} 
        cartCount={cart.reduce((acc, item) => acc + item.quantity, 0)}
        userRole={userRole}
        onLogout={handleLogout}
      />
      <main className="animate-in fade-in duration-300">
        {renderView()}
      </main>
    </div>
  );
};

export default App;

