import React, { useState } from 'react';
import { Order, UserRole } from '../types';
import { Package, Truck, CheckCircle2, Clock, MapPin, Phone } from 'lucide-react';

interface OrdersProps {
  orders: Order[];
  userRole: UserRole | null;
  title?: string;
  onUpdateStatus?: (orderId: string, newStatus: Order['status']) => void;
}

export const Orders: React.FC<OrdersProps> = ({ orders, userRole, title = "الطلبات", onUpdateStatus }) => {
  const [activeTab, setActiveTab] = useState<'purchases' | 'sales'>('purchases');

  // Filter logic could be more complex with real backend, here we just show passed orders
  // In a real app, Farmer would toggle between "What I bought" vs "What I sold"
  const isTransport = userRole === UserRole.TRANSPORT;
  const isFarmer = userRole === UserRole.FARMER;

  if (orders.length === 0) {
    return (
      <div className="p-10 text-center max-w-4xl mx-auto">
        <div className="bg-gray-100 w-24 h-24 rounded-full flex items-center justify-center mx-auto mb-6">
          <Package className="h-10 w-10 text-gray-400" />
        </div>
        <h2 className="text-2xl font-bold text-gray-800 mb-2">لا توجد طلبات</h2>
        <p className="text-gray-500">
          {isTransport ? "لا توجد شحنات متاحة للتوصيل حالياً." : "لم تقم بإجراء أي عمليات بعد."}
        </p>
      </div>
    );
  }

  const getStatusColor = (status: string) => {
    switch(status) {
      case 'pending': return 'bg-yellow-100 text-yellow-800 border-yellow-200';
      case 'shipping': return 'bg-blue-100 text-blue-800 border-blue-200';
      case 'delivered': return 'bg-green-100 text-green-800 border-green-200';
      default: return 'bg-gray-100 text-gray-800';
    }
  };

  const getStatusText = (status: string) => {
     switch(status) {
      case 'pending': return 'قيد التجهيز';
      case 'shipping': return 'جاري التوصيل';
      case 'delivered': return 'تم التسليم';
      default: return status;
    }
  };

  return (
    <div className="p-6 max-w-5xl mx-auto">
      <div className="flex flex-col md:flex-row justify-between items-center mb-8 gap-4">
        <h2 className="text-3xl font-bold text-gray-800">{title}</h2>
        {isFarmer && (
          <div className="bg-gray-100 p-1 rounded-lg flex">
             <button 
               onClick={() => setActiveTab('purchases')}
               className={`px-4 py-2 rounded-md text-sm font-bold transition-all ${activeTab === 'purchases' ? 'bg-white shadow text-primary-600' : 'text-gray-500'}`}
             >
               مشترياتي
             </button>
             <button 
               onClick={() => setActiveTab('sales')}
               className={`px-4 py-2 rounded-md text-sm font-bold transition-all ${activeTab === 'sales' ? 'bg-white shadow text-primary-600' : 'text-gray-500'}`}
             >
               مبيعاتي (وارد)
             </button>
          </div>
        )}
      </div>

      <div className="space-y-6">
        {orders.map((order) => (
          <div key={order.id} className="bg-white rounded-xl shadow-sm border border-gray-200 overflow-hidden hover:shadow-md transition">
            <div className="bg-gray-50 p-4 border-b border-gray-200 flex flex-wrap gap-4 justify-between items-center">
              <div className="flex gap-6 text-sm text-gray-600">
                <div>
                  <span className="block text-xs text-gray-400">تاريخ الطلب</span>
                  <span className="font-medium">{order.date}</span>
                </div>
                <div>
                  <span className="block text-xs text-gray-400">رقم الطلب</span>
                  <span className="font-medium">#{order.id.slice(-6)}</span>
                </div>
                 {isTransport && (
                    <div>
                      <span className="block text-xs text-gray-400">الموقع</span>
                      <span className="font-medium flex items-center gap-1"><MapPin className="h-3 w-3" /> الحديدة - باجل</span>
                    </div>
                 )}
              </div>
              <div className={`px-4 py-1.5 rounded-full border flex items-center gap-2 text-sm font-bold ${getStatusColor(order.status)}`}>
                 {order.status === 'shipping' ? <Truck className="h-4 w-4" /> : <Package className="h-4 w-4" />}
                 {getStatusText(order.status)}
              </div>
            </div>

            <div className="p-6">
              <div className="space-y-4">
                 {order.items.map((item, idx) => (
                   <div key={idx} className="flex items-center justify-between border-b border-gray-50 last:border-0 pb-2 last:pb-0">
                     <div className="flex items-center gap-4">
                        <img src={item.image} alt={item.name} className="w-16 h-16 rounded-md object-cover" />
                        <div>
                           <h4 className="font-bold text-gray-800">{item.name}</h4>
                           <p className="text-sm text-gray-500">البائع: {item.sellerName}</p>
                        </div>
                     </div>
                     <div className="text-left">
                        <span className="block font-bold text-gray-800">{item.price} ريال</span>
                        <span className="text-sm text-gray-500">الكمية: {item.quantity}</span>
                     </div>
                   </div>
                 ))}
              </div>

              <div className="mt-6 pt-4 border-t border-gray-100 flex flex-col md:flex-row justify-between items-center gap-4">
                 {/* Total */}
                 <div className="text-lg font-bold text-gray-900">
                    الإجمالي: {order.total} ريال
                 </div>

                 {/* Transport Actions */}
                 {isTransport && onUpdateStatus && (
                   <div className="flex gap-2">
                     {order.status === 'pending' && (
                       <button 
                         onClick={() => onUpdateStatus(order.id, 'shipping')}
                         className="bg-blue-600 text-white px-4 py-2 rounded-lg text-sm font-bold hover:bg-blue-700 flex items-center gap-2"
                       >
                         <Truck className="h-4 w-4" />
                         بدء التوصيل
                       </button>
                     )}
                     {order.status === 'shipping' && (
                       <button 
                         onClick={() => onUpdateStatus(order.id, 'delivered')}
                         className="bg-green-600 text-white px-4 py-2 rounded-lg text-sm font-bold hover:bg-green-700 flex items-center gap-2"
                       >
                         <CheckCircle2 className="h-4 w-4" />
                         تأكيد التسليم
                       </button>
                     )}
                     <button className="bg-gray-100 text-gray-700 px-4 py-2 rounded-lg text-sm font-bold hover:bg-gray-200 flex items-center gap-2">
                        <Phone className="h-4 w-4" />
                        اتصال بالعميل
                     </button>
                   </div>
                 )}

                 {/* Consumer Tracking */}
                 {!isTransport && order.trackingNumber && (
                    <div className="flex items-center gap-2 text-primary-700 bg-primary-50 px-3 py-1 rounded-lg">
                       <Truck className="h-4 w-4" />
                       <span className="text-sm font-medium">تتبع: {order.trackingNumber}</span>
                    </div>
                 )}
              </div>
            </div>
          </div>
        ))}
      </div>
    </div>
  );
};

