            </div>

            <div className="p-6">
              <div className="space-y-4">
                 {order.items.map((item, idx) => (
                   <div key={idx} className="flex items-center justify-between border-b border-gray-50 last:border-0 pb-2 last:pb-0">
                     <div className="flex items-center gap-4">
                        <img src={item.image} alt={item.name} className="w-16 h-16 rounded-md object-cover" />
                        <div>
                           <h4 className="font-bold text-gray-800">{item.name}</h4>
                           <p className="text-sm text-gray-500">البائع: {item.sellerName}</p>
                        </div>
                     </div>
                     <div className="text-left">
                        <span className="block font-bold text-gray-800">{item.price} ريال</span>
                        <span className="text-sm text-gray-500">الكمية: {item.quantity}</span>
                     </div>
                   </div>
                 ))}
              </div>

              <div className="mt-6 pt-4 border-t border-gray-100 flex flex-col md:flex-row justify-between items-center gap-4">
                 {/* Total */}
                 <div className="text-lg font-bold text-gray-900">
                    الإجمالي: {order.total} ريال
                 </div>

                 {/* Transport Actions */}
                 {isTransport && onUpdateStatus && (
                   <div className="flex gap-2">
                     {order.status === 'pending' && (
                       <button 
                         onClick={() => onUpdateStatus(order.id, 'shipping')}
                         className="bg-blue-600 text-white px-4 py-2 rounded-lg text-sm font-bold hover:bg-blue-700 flex items-center gap-2"
                       >
                         <Truck className="h-4 w-4" />
                         بدء التوصيل
                       </button>
                     )}
                     {order.status === 'shipping' && (
                       <button 
                         onClick={() => onUpdateStatus(order.id, 'delivered')}
                         className="bg-green-600 text-white px-4 py-2 rounded-lg text-sm font-bold hover:bg-green-700 flex items-center gap-2"
                       >
                         <CheckCircle2 className="h-4 w-4" />
                         تأكيد التسليم
                       </button>
                     )}
                     <button className="bg-gray-100 text-gray-700 px-4 py-2 rounded-lg text-sm font-bold hover:bg-gray-200 flex items-center gap-2">
                        <Phone className="h-4 w-4" />
                        اتصال بالعميل
                     </button>
                   </div>
                 )}

                 {/* Consumer Tracking */}
                 {!isTransport && order.trackingNumber && (
                    <div className="flex items-center gap-2 text-primary-700 bg-primary-50 px-3 py-1 rounded-lg">
                       <Truck className="h-4 w-4" />
                       <span className="text-sm font-medium">تتبع: {order.trackingNumber}</span>
                    </div>
                 )}
              </div>
            </div>
          </div>
        ))}
      </div>
    </div>
  );
};

