}

export const Navigation: React.FC<NavigationProps> = ({ currentView, setView, cartCount, userRole, onLogout }) => {
  const [isOpen, setIsOpen] = useState(false);
  const [showNotifications, setShowNotifications] = useState(false);

  // Define navigation items with specific role access
  const navItems = [
    { 
      id: 'home', 
      label: 'الرئيسية', 
      icon: Home, 
      roles: ['all'] 
    },
    { 
      id: 'market', 
      label: 'السوق', 
      icon: ShoppingCart, 
      roles: [UserRole.CONSUMER, UserRole.MERCHANT, UserRole.FARMER, UserRole.ADMIN, UserRole.ASSOCIATION] 
    },
    { 
      id: 'orders', 
      label: userRole === UserRole.FARMER ? 'المبيعات والطلبات' : (userRole === UserRole.ASSOCIATION ? 'متابعة الطلبات' : 'طلباتي'), 
      icon: Package, 
      roles: [UserRole.CONSUMER, UserRole.MERCHANT, UserRole.FARMER, UserRole.ASSOCIATION] 
    },
    { 
      id: 'shipments', 
      label: 'شحنات للتوصيل', 
      icon: Truck, 
      roles: [UserRole.TRANSPORT] 
    },
    { 
      id: 'messages', 
      label: 'الرسائل', 
      icon: MessageCircle, 
      roles: ['all'] 
    },
    { 
      id: 'dashboard', 
      label: 'لوحة التحكم', 
      icon: BarChart3, 
      roles: [UserRole.ADMIN, UserRole.ASSOCIATION] 
    },
