    { 
      id: 'advisor', 
      label: 'المرشد الذكي', 
      icon: Sprout, 
      roles: ['all'] 
    },
  ];

  const filteredItems = navItems.filter(item => 
    item.roles.includes('all') || (userRole && item.roles.includes(userRole))
  );

  const mockNotifications = [
    { id: 1, text: 'ارتفاع في أسعار المانجو بنسبة 10%', time: 'منذ ساعة', type: 'info' },
