            <div className="bg-white/10 p-1 rounded-lg">
              <Sprout className="h-7 w-7 text-primary-100" />
            </div>
            <div>
              <span className="font-bold text-lg tracking-wide block leading-none">عطاء تهامة</span>
              {userRole && <span className="text-xs text-primary-200 font-light">{userRole}</span>}
            </div>
          </div>

