          <div className="flex items-center gap-2 cursor-pointer" onClick={() => setView('home')}>
            <div className="bg-white/10 p-1 rounded-lg">
              <Sprout className="h-7 w-7 text-primary-100" />
            </div>
            <div>
              <span className="font-bold text-lg tracking-wide block leading-none">عطاء تهامة</span>
              {userRole && <span className="text-xs text-primary-200 font-light">{userRole}</span>}
            </div>
          </div>

          {/* Desktop Nav */}
          <div className="hidden xl:block">
            <div className="ml-10 flex items-baseline space-x-2 space-x-reverse">
              {filteredItems.map((item) => (
                <button
                  key={item.id}
                  onClick={() => setView(item.id)}
                  className={`px-3 py-2 rounded-md text-sm font-medium transition-colors duration-200 flex items-center gap-2 ${
                    currentView === item.id
                      ? 'bg-primary-800 text-white shadow-inner'
                      : 'text-primary-100 hover:bg-primary-600'
                  }`}
                >
                  <item.icon className="h-4 w-4" />
                  {item.label}
                </button>
              ))}
            </div>
          </div>

          <div className="flex items-center gap-3">
             {/* Notifications */}
             <div className="relative">
                <button 
                  onClick={() => setShowNotifications(!showNotifications)}
                  className="p-2 rounded-full hover:bg-primary-600 transition-colors relative"
                >
                  <Bell className="h-6 w-6 text-primary-100" />
                  <span className="absolute top-1 right-1 h-2.5 w-2.5 bg-red-500 rounded-full border-2 border-primary-700"></span>
                </button>

                {showNotifications && (
                  <div className="absolute left-0 mt-2 w-72 bg-white rounded-xl shadow-xl overflow-hidden z-50 text-gray-800 border border-gray-100">
                    <div className="p-3 border-b bg-gray-50 font-bold text-sm">الإشعارات</div>
                    <div className="max-h-64 overflow-y-auto">
                      {mockNotifications.map(notif => (
                        <div key={notif.id} className="p-3 border-b hover:bg-gray-50 cursor-pointer">
                          <p className="text-sm font-medium text-gray-800">{notif.text}</p>
                          <span className="text-xs text-gray-500 block mt-1">{notif.time}</span>
                        </div>
                      ))}
                    </div>
                  </div>
                )}
             </div>

             {/* Cart Icon - Hide for Transport & Association */}
             {userRole !== UserRole.TRANSPORT && userRole !== UserRole.ASSOCIATION && (
               <button 
                  onClick={() => setView('cart')}
                  className="relative p-2 rounded-full hover:bg-primary-600 transition-colors"
                >
                  <ShoppingCart className="h-6 w-6 text-primary-100" />
                  {cartCount > 0 && (
                    <span className="absolute top-0 right-0 inline-flex items-center justify-center px-2 py-1 text-xs font-bold leading-none text-white transform translate-x-1/4 -translate-y-1/4 bg-red-600 rounded-full">
                      {cartCount}
                    </span>
                  )}
                </button>
             )}

             {/* Logout / User */}
             {userRole ? (
               <button 
                onClick={onLogout}
                className="hidden md:flex items-center gap-1 text-xs bg-primary-800 px-3 py-1.5 rounded-full hover:bg-red-600 transition-colors"
               >
                 <LogOut className="h-3 w-3" />
                 خروج
               </button>
             ) : (
               <div className="hidden md:flex items-center gap-1 text-xs text-primary-200">
                 <User className="h-4 w-4" />
                 زائر
               </div>
             )}

            {/* Mobile Menu Button */}
            <div className="-mr-2 flex xl:hidden">
              <button
                onClick={() => setIsOpen(!isOpen)}
                className="bg-primary-800 inline-flex items-center justify-center p-2 rounded-md text-primary-100 hover:text-white hover:bg-primary-600 focus:outline-none"
              >
                <Menu className="h-6 w-6" />
              </button>
            </div>
          </div>
        </div>
      </div>

      {/* Mobile Menu */}
      {isOpen && (
        <div className="xl:hidden bg-primary-800 border-t border-primary-600">
          <div className="px-2 pt-2 pb-3 space-y-1 sm:px-3">
            {filteredItems.map((item) => (
              <button
                key={item.id}
                onClick={() => {
                  setView(item.id);
                  setIsOpen(false);
                }}
                className={`block w-full text-right px-3 py-2 rounded-md text-base font-medium ${
                   currentView === item.id
                      ? 'bg-primary-900 text-white'
                      : 'text-primary-100 hover:bg-primary-600'
                }`}
              >
                <div className="flex items-center gap-2">
                   <item.icon className="h-5 w-5" />
                   {item.label}
                </div>
              </button>
            ))}
            {userRole && (
               <button
                onClick={() => {
                  onLogout();
                  setIsOpen(false);
                }}
                className="block w-full text-right px-3 py-2 rounded-md text-base font-medium text-red-300 hover:bg-red-900/20"
              >
                <div className="flex items-center gap-2">
                   <LogOut className="h-5 w-5" />
                   تسجيل الخروج
                </div>
              </button>
            )}
          </div>
        </div>
      )}
    </nav>
  );
};

export enum UserRole {
  FARMER = 'مزارع',
  MERCHANT = 'تاجر',
  CONSUMER = 'مستهلك',
  TRANSPORT = 'شركة نقل',
  ASSOCIATION = 'جمعية زراعية',
  ADMIN = 'مشرف'
}

export enum ProductCategory {
  VEGETABLES = 'خضروات',
  FRUITS = 'فواكه',
  GRAINS = 'حبوب',
  LIVESTOCK = 'مواشي',
  FERTILIZERS = 'أسمدة ومبيدات'
}

export interface UserProfile {
  id: string;
  name: string;
  phone: string;
  email?: string;
  role: UserRole;
  governorate?: string;
  district?: string;
  area?: string;
  association?: string; // For Farmers
  tradeType?: string; // For Merchants (Retail, Wholesale, Export)
  isVerified: boolean;
  associationVerified?: boolean; // If farmer is approved by association
}

export interface Product {
  id: string;
  name: string;
  category: ProductCategory;
  price: number;
  unit: string;
  image: string;
  sellerName: string;
  associationName?: string; // Link product to an association
  location: string;
  description: string;
}

export interface CartItem extends Product {
  quantity: number;
}

export interface Order {
  id: string;
  items: CartItem[];
  total: number;
  status: 'pending' | 'shipping' | 'delivered';
  date: string;
  trackingNumber?: string;
  associationName?: string; // To route the order
}

export interface Article {
  id: string;
  title: string;
  category: string;
  summary: string;
  content: string;
  date: string;
  image: string;
}

export interface MarketStat {
  name: string;
  price: number;
  demand: number; // 0-100 scale
}

export interface ChatMessage {
  id: string;
  role: 'user' | 'model';
  text: string;
  timestamp: Date;
}

export interface UserConversation {
  id: string;
  contactName: string;
  lastMessage: string;
  timestamp: string;
  unread: number;
  avatar: string;
}

