interface MarketplaceProps {
  products: Product[];
  onAddToCart: (product: Product) => void;
  onContact: (sellerId: string) => void;
  onProductClick: (product: Product) => void;
}

type SortOption = 'newest' | 'price-asc' | 'price-desc';

const CATEGORY_ICONS: Record<string, React.ReactNode> = {
  [ProductCategory.VEGETABLES]: <Leaf className="h-4 w-4" />,
  [ProductCategory.FRUITS]: <ShoppingBasket className="h-4 w-4" />,
  [ProductCategory.GRAINS]: <Wheat className="h-4 w-4" />,
  // Fallback icon
  'default': <Tag className="h-4 w-4" />
};

export const Marketplace: React.FC<MarketplaceProps> = ({ products, onAddToCart, onContact, onProductClick }) => {
  const [filter, setFilter] = useState<string>('all');
  const [searchTerm, setSearchTerm] = useState('');
  const [sortOption, setSortOption] = useState<SortOption>('newest');

  const filteredProducts = products.filter(p => {
    const matchesCategory = filter === 'all' || p.category === filter;
    const matchesSearch = p.name.includes(searchTerm) || p.sellerName.includes(searchTerm) || p.associationName?.includes(searchTerm);
    return matchesCategory && matchesSearch;
  }).sort((a, b) => {
    if (sortOption === 'price-asc') return a.price - b.price;
    if (sortOption === 'price-desc') return b.price - a.price;
    // Mock newest (using ID as proxy for now)
    return Number(b.id) - Number(a.id);
  });

  return (
    <div className="p-4 md:p-6 max-w-7xl mx-auto min-h-screen">

