const INITIAL_ORDERS: Order[] = [];

export const App: React.FC = () => {
  const [view, setView] = useState('home');
  const [userRole, setUserRole] = useState<UserRole | null>(null);
  const [cart, setCart] = useState<CartItem[]>([]);
  const [products, setProducts] = useState<Product[]>(INITIAL_PRODUCTS);
  const [orders, setOrders] = useState<Order[]>(INITIAL_ORDERS);
  const [selectedProduct, setSelectedProduct] = useState<Product | null>(null);
  const [chatTarget, setChatTarget] = useState<string | undefined>(undefined);

  const [userProfile, setUserProfile] = useState<UserProfile | null>(null);

  // Login Form State
  const [loginForm, setLoginForm] = useState({ name: '', phone: '', role: UserRole.CONSUMER, association: '' });

  const handleLogin = (e: React.FormEvent) => {
    e.preventDefault();
    const profile: UserProfile = {
      id: Date.now().toString(),
      name: loginForm.name,
      phone: loginForm.phone,
      role: loginForm.role,
      association: loginForm.association,
      isVerified: true, // Mock verification
      associationVerified: true
    };
    setUserProfile(profile);
    setUserRole(loginForm.role);
    setView('home'); // Go to home after login, menu will adapt
    setOrders([]); 
  };

  const checkAuth = () => {
    if (!userRole) {
      setView('login');
      return false;
    }
    return true;
  };

  const addToCart = (product: Product) => {
    if (!checkAuth()) return;

    setCart(prev => {
      const existing = prev.find(p => p.id === product.id);
      if (existing) {
        return prev.map(p => p.id === product.id ? { ...p, quantity: p.quantity + 1 } : p);
      }
      return [...prev, { ...product, quantity: 1 }];
    });
    // Optional: show toast
  };

  const removeFromCart = (id: string) => {
    setCart(prev => prev.filter(item => item.id !== id));
  };

  const handleCheckout = () => {
    const newOrder: Order = {
      id: `ord-${Date.now()}`,
      items: cart,
      total: cart.reduce((sum, item) => sum + (item.price * item.quantity), 0) + 2000,
      status: 'pending',
      date: new Date().toISOString().split('T')[0],
      associationName: cart[0]?.associationName // Simplification
    };
    setOrders(prev => [newOrder, ...prev]);
    setCart([]);
  };

  const handleAddProduct = (newProduct: Product) => {
    setProducts(prev => [newProduct, ...prev]);
    setView('market');
  };

  const handleUpdateOrderStatus = (orderId: string, newStatus: Order['status']) => {
    setOrders(prev => prev.map(o => o.id === orderId ? { ...o, status: newStatus } : o));
  };

  const handleProductClick = (product: Product) => {
    setSelectedProduct(product);
    setView('product-details');
  };

  const handleContactSeller = (sellerName: string) => {
    if (!checkAuth()) return;
    setChatTarget(sellerName);
    setView('messages');
  };

  // Determine if orders menu should be visible
  const hasOrders = useMemo(() => {
    if (!userRole) return false;

    // For Farmers/Merchants (Sales view): check if they have incoming sales
    if ((userRole === UserRole.FARMER || userRole === UserRole.MERCHANT) && userProfile) {
       // Check sales
       const hasSales = orders.some(o => o.items.some(i => i.sellerName === userProfile.name));
       // Check purchases (if they bought something)
       const hasPurchases = orders.some(o => !o.items.some(i => i.sellerName === userProfile.name)); // Simplified logic

       // For this demo, orders state contains ALL orders relevant to session.
       // So if orders is not empty, we show it.
       return orders.length > 0;
    }

    // For Consumers
    return orders.length > 0;
  }, [orders, userRole, userProfile]);

  // --- Login View Component ---
  const LoginView = () => (
    <div className="min-h-[calc(100vh-80px)] bg-gray-50 flex items-center justify-center p-4" dir="rtl">
      <div className="bg-white p-8 rounded-2xl shadow-xl w-full max-w-md border border-gray-100 animate-in fade-in zoom-in-95 duration-200">
        <div className="text-center mb-8">
          <div className="bg-primary-50 w-20 h-20 rounded-full flex items-center justify-center mx-auto mb-4">
              <Sprout className="h-10 w-10 text-primary-600" />
          </div>
          <h1 className="text-3xl font-extrabold text-gray-900 mb-2">تسجيل الدخول</h1>
          <p className="text-gray-500">مرحباً بك مجدداً في عطاء تهامة</p>
        </div>

        <form onSubmit={handleLogin} className="space-y-5">
          <div>
            <label className="block text-sm font-bold text-gray-700 mb-1">الاسم الكامل</label>
            <input 
              required
              type="text" 
              className="w-full px-4 py-3 border border-gray-300 rounded-xl focus:ring-2 focus:ring-primary-500 outline-none transition-all"
              placeholder="أدخل اسمك"
              value={loginForm.name}
              onChange={e => setLoginForm({...loginForm, name: e.target.value})}
            />
          </div>

          <div>
            <label className="block text-sm font-bold text-gray-700 mb-1">رقم الهاتف</label>
            <input 
              required
              type="tel" 
              className="w-full px-4 py-3 border border-gray-300 rounded-xl focus:ring-2 focus:ring-primary-500 outline-none transition-all"
              placeholder="77xxxxxxx"
              value={loginForm.phone}
              onChange={e => setLoginForm({...loginForm, phone: e.target.value})}
            />
          </div>

          <div>
            <label className="block text-sm font-bold text-gray-700 mb-1">نوع المستخدم</label>
            <div className="grid grid-cols-2 gap-3">
              {[UserRole.FARMER, UserRole.MERCHANT, UserRole.CONSUMER, UserRole.TRANSPORT, UserRole.ASSOCIATION].map(role => (
                <button
                  key={role}
                  type="button"
                  onClick={() => setLoginForm({...loginForm, role: role})}
                  className={`p-3 rounded-xl border text-sm font-bold transition-all ${
                    loginForm.role === role 
                      ? 'bg-primary-600 text-white border-primary-600 shadow-md transform scale-[1.02]' 
                      : 'bg-white text-gray-600 border-gray-200 hover:bg-gray-50'
                  }`}
                >
                  {role}
                </button>
              ))}
            </div>
          </div>

          {/* Association Selection for Farmers */}
          {loginForm.role === UserRole.FARMER && (
            <div className="animate-in fade-in slide-in-from-top-2">
              <label className="block text-sm font-bold text-gray-700 mb-1">الجمعية الزراعية (اختياري)</label>
              <select
                className="w-full px-4 py-3 border border-gray-300 rounded-xl focus:ring-2 focus:ring-primary-500 outline-none bg-white"
                value={loginForm.association}
                onChange={e => setLoginForm({...loginForm, association: e.target.value})}
              >
                <option value="">-- اختر الجمعية --</option>
                {REGISTERED_SYSTEM_ASSOCIATIONS.map(assoc => (
                  <option key={assoc} value={assoc}>{assoc}</option>
                ))}
              </select>
              <p className="text-xs text-gray-400 mt-1">الانضمام لجمعية يمنح منتجاتك شارة "موثق"</p>
            </div>
          )}

          <button 
            type="submit" 
            className="w-full bg-primary-700 text-white py-4 rounded-xl font-bold text-lg hover:bg-primary-800 transition-colors shadow-lg mt-4"
          >
            دخول للمنصة
          </button>

          <button 
            type="button"
            onClick={() => {
              setUserRole(UserRole.GUEST);
              setView('home');
            }}
            className="w-full bg-gray-100 text-gray-600 py-3 rounded-xl font-bold hover:bg-gray-200 transition-colors"
          >
            تصفح كزائر
          </button>
        </form>
      </div>
    </div>
  );

  return (
    <div className="min-h-screen bg-gray-50 font-sans flex flex-col" dir="rtl">
      <Navigation 
        currentView={view} 
        setView={setView} 
        cartCount={cart.reduce((a, b) => a + b.quantity, 0)}
        userRole={userRole}
        onLogout={() => {
          setUserRole(null);
          setUserProfile(null);
          setView('home'); // Go to home after logout
          setOrders([]); // Reset orders on logout
        }}
        hasOrders={hasOrders}
      />

      <main className="flex-1 pb-10">
        {view === 'login' && <LoginView />}

        {view === 'home' && (
          <div className="space-y-12">
            <div className="max-w-7xl mx-auto px-4 pt-8">
              {/* Hero Section */}
              <div className="bg-white rounded-3xl shadow-xl overflow-hidden relative border border-gray-100">
                <div className="grid md:grid-cols-2 items-center">
                  <div className="p-8 md:p-12 z-10">
                    <span className="bg-primary-100 text-primary-800 text-sm font-bold px-3 py-1 rounded-full mb-4 inline-block">
                      موسم حصاد المانجو 🥭
                    </span>
                    <h1 className="text-4xl md:text-5xl font-extrabold text-gray-900 mb-6 leading-tight">
                      من خيرات <span className="text-primary-600">تهامة</span><br />
                      إلى مائدتك مباشرة
                    </h1>
                    <p className="text-gray-600 text-lg mb-8 leading-relaxed">
                      منصة "عطاء تهامة" تجمع المزارعين، التجار، والمستهلكين في سوق رقمي واحد. 
                      نضمن لك الجودة، السعر العادل، والتوصيل السريع.
                    </p>
                    <div className="flex flex-wrap gap-4">
                      <button 
                        onClick={() => setView('market')}
                        className="bg-primary-600 text-white px-8 py-3 rounded-xl font-bold hover:bg-primary-700 transition shadow-lg flex items-center gap-2"
                      >
                        <Store className="h-5 w-5" />
                        تصفح السوق
                      </button>
                      <button 
                        onClick={() => setView('advisor')}
                        className="bg-white text-primary-700 border-2 border-primary-100 px-8 py-3 rounded-xl font-bold hover:border-primary-600 transition flex items-center gap-2"
                      >
                        <Sprout className="h-5 w-5" />
                        المرشد الزراعي
                      </button>
                    </div>
                  </div>
                  <div className="h-64 md:h-full bg-gray-100 relative">
                    <img 
                      src="https://images.unsplash.com/photo-1625246333195-0985250428d0?ixlib=rb-4.0.3&auto=format&fit=crop&w=1000&q=80" 
                      className="w-full h-full object-cover"
                      alt="Farm"
                    />
                    <div className="absolute inset-0 bg-gradient-to-r from-white/80 to-transparent md:from-white md:via-transparent"></div>
                  </div>
                </div>
              </div>

              {/* Features Grid */}
              <div className="grid md:grid-cols-3 gap-8 mt-12">
                 <div className="bg-white p-6 rounded-2xl shadow-sm border border-gray-100 hover:shadow-md transition">
                    <div className="bg-green-100 w-12 h-12 rounded-xl flex items-center justify-center text-green-600 mb-4">
                       <ShieldCheck className="h-6 w-6" />
                    </div>
                    <h3 className="text-xl font-bold text-gray-900 mb-2">منتجات موثقة</h3>
                    <p className="text-gray-500 leading-relaxed">
                       نتعاون مع الجمعيات الزراعية للتأكد من جودة المحاصيل ومصداقية المزارعين.
                    </p>
                 </div>
                 <div className="bg-white p-6 rounded-2xl shadow-sm border border-gray-100 hover:shadow-md transition">
                    <div className="bg-blue-100 w-12 h-12 rounded-xl flex items-center justify-center text-blue-600 mb-4">
                       <Truck className="h-6 w-6" />
                    </div>
                    <h3 className="text-xl font-bold text-gray-900 mb-2">سلاسل إمداد ذكية</h3>
                    <p className="text-gray-500 leading-relaxed">
                       نربط المزارع بشركات النقل والتجار لتقليل التالف وضمان وصول المنتج طازجاً.
                    </p>
                 </div>
                 <div className="bg-white p-6 rounded-2xl shadow-sm border border-gray-100 hover:shadow-md transition">
                    <div className="bg-orange-100 w-12 h-12 rounded-xl flex items-center justify-center text-orange-600 mb-4">
                       <BarChart className="h-6 w-6" />
                    </div>
                    <h3 className="text-xl font-bold text-gray-900 mb-2">بيانات السوق</h3>
                    <p className="text-gray-500 leading-relaxed">
                       نوفر بيانات لحظية عن الأسعار والطلب لمساعدة المزارع على اتخاذ القرار الصحيح.
                    </p>
                 </div>
              </div>

              {/* Recent Products Preview */}
              <div className="mt-16">
                 <div className="flex justify-between items-center mb-8">
                    <h2 className="text-2xl font-bold text-gray-900">أحدث المنتجات المضافة</h2>
                    <button onClick={() => setView('market')} className="text-primary-600 font-bold hover:underline">عرض الكل &larr;</button>
                 </div>
                 <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6">
                    {products.slice(0, 4).map(product => (
                       <div key={product.id} className="bg-white rounded-2xl shadow-sm border border-gray-100 overflow-hidden hover:shadow-lg transition-all cursor-pointer" onClick={() => handleProductClick(product)}>
                          <div className="h-40 bg-gray-100 relative">
                             <img src={product.image} alt={product.name} className="w-full h-full object-cover" />
                             <span className="absolute top-2 right-2 bg-white/90 px-2 py-1 text-xs font-bold rounded-md text-gray-700">{product.category}</span>
                          </div>
                          <div className="p-4">
                             <h3 className="font-bold text-gray-800 mb-1">{product.name}</h3>
                             <div className="flex justify-between items-center">
                                <span className="text-primary-600 font-bold">{product.price} ريال</span>
                                <span className="text-gray-400 text-xs">{product.unit}</span>
                             </div>
                          </div>
                       </div>
                    ))}
                 </div>
              </div>

              {/* CTA Section */}
              <div className="bg-gray-900 rounded-3xl p-8 md:p-12 text-center text-white relative overflow-hidden mt-16">
                 <div className="relative z-10 max-w-2xl mx-auto">
                    <h2 className="text-3xl font-bold mb-4">هل أنت مزارع؟ انضم إلينا اليوم</h2>
                    <p className="text-gray-400 mb-8">
                       سجل منتجاتك، تواصل مع التجار، واحصل على إرشادات زراعية متخصصة لرفع إنتاجية أرضك.
                    </p>
                    <button 
                      onClick={() => {
                          if (userRole) {
                              setView('dashboard'); // Assuming authenticated
                          } else {
                              setUserRole(null); // Ensure null to trigger login flow properly
                              setLoginForm({...loginForm, role: UserRole.FARMER});
                              setView('login');
                          }
                      }}
                      className="bg-primary-500 text-white px-8 py-3 rounded-full font-bold hover:bg-primary-600 transition shadow-lg shadow-primary-500/30"
                    >
                       ابدأ البيع الآن
                    </button>
                 </div>
                 <div className="absolute top-0 left-0 w-full h-full opacity-10 bg-[url('https://www.transparenttextures.com/patterns/cubes.png')]"></div>
              </div>
            </div>
          </div>
        )}

        {view === 'market' && (
          <Marketplace 
            products={products} 
            onAddToCart={addToCart} 
            onContact={handleContactSeller}
            onProductClick={handleProductClick}
          />
        )}

        {view === 'product-details' && selectedProduct && (
          <ProductDetails 
            product={selectedProduct}
            onBack={() => setView('market')}
            onAddToCart={addToCart}
            onContact={(sellerName) => {
              if (checkAuth()) {
                handleContactSeller(sellerName);
              }
            }}
          />
        )}

        {view === 'cart' && (
          <Cart 
            items={cart} 
            onRemove={removeFromCart} 
            onCheckout={handleCheckout} 
          />
        )}

        {view === 'orders' && (
          <Orders 
            orders={orders} 
            userRole={userRole} 
            userName={userProfile?.name}
            onUpdateStatus={handleUpdateOrderStatus}
          />
        )}

        {view === 'add-product' && userProfile && (
          <ProductForm 
            onAddProduct={handleAddProduct} 
            onCancel={() => setView('market')}
            userProfile={userProfile}
          />
        )}

        {view === 'advisor' && <AIAdvisor />}

        {view === 'guidance' && <GuidanceLibrary />}

        {view === 'dashboard' && <StatsDashboard />}

        {view === 'messages' && (
           <UserChat initialContact={chatTarget} />
        )}

        {view === 'shipments' && (
           <Orders 
             orders={orders.filter(o => o.status === 'shipping' || o.status === 'pending')} 
             userRole={userRole} 
             title="الشحنات المتاحة والحالية"
             onUpdateStatus={handleUpdateOrderStatus}
           />
        )}
      </main>

      {/* Footer only on non-app views (like Home, Guidance, Public Market) or always? Usually always. */}
      {view !== 'messages' && view !== 'cart' && <Footer />}
    </div>
  );
};

