            <Home className="h-6 w-6" />
            <span className="text-[10px] font-bold">الرئيسية</span>
         </NavLink>
         <NavLink to="/market" className={({ isActive }) => `flex flex-col items-center gap-1 ${isActive ? 'text-green-600' : 'text-gray-400'}`}>
