         </NavLink>
         <NavLink to="/advisor" className={() => `flex flex-col items-center gap-1 ${isPathActive('/advisor') ? 'text-green-600' : 'text-gray-400'}`}>
            <div className={`p-3 -mt-10 rounded-2xl shadow-lg border-4 border-white transform transition-transform ${isPathActive('/advisor') ? 'bg-green-600 text-white scale-110' : 'bg-green-700 text-white'}`}>
               <Bot className="h-7 w-7" />
            </div>
            <span className="text-[10px] font-bold">المرشد</span>
         </NavLink>
         <NavLink to="/messages" className={() => `flex flex-col items-center gap-1 ${isPathActive('/messages') ? 'text-green-600' : 'text-gray-400'}`}>
            <MessageSquare className="h-6 w-6" />
            <span className="text-[10px] font-bold">الرسائل</span>
         </NavLink>
         <NavLink to="/orders" className={() => `flex flex-col items-center gap-1 ${isPathActive('/orders') ? 'text-green-600' : 'text-gray-400'}`}>
            <Package className="h-6 w-6" />
            <span className="text-[10px] font-bold">طلباتي</span>
         </NavLink>
      </nav>

      {(location.pathname === '/' || !userRole) && <Footer />}
    </div>
  );
};
